-                                       WithoutRuntimeCheck);
-  }
-  VPlanTransforms::optimizeInductionExitUsers(*Plan, IVEndValues);
-
-  assert(verifyVPlanIsValid(*Plan) && "VPlan is invalid");
-  return Plan;
-}
