-      VPValue *VPV = Plan.getOrAddLiveIn(EPResumeVal);
-      assert(all_of(IV->users(),
-                    [](const VPUser *U) {
-                      return isa<VPScalarIVStepsRecipe>(U) ||
-                             isa<VPScalarCastRecipe>(U) ||
-                             isa<VPDerivedIVRecipe>(U) ||
-                             cast<VPInstruction>(U)->getOpcode() ==
