-
-  if (LVL.hasUncountableEarlyExit()) {
-    BasicBlock *LoopLatch = L->getLoopLatch();
-    if (IAI.requiresScalarEpilogue() ||
-        any_of(LVL.getCountableExitingBlocks(),
-               [LoopLatch](BasicBlock *BB) { return BB != LoopLatch; })) {
